skills.contentCode:
const enemies = Effect.getEnemiesInRange(actor, { shape: 'r', n: 1 });
if (enemies.length === 0) { Game.log('周围没有敌人！', 'turn'); return; }
Effect.showMarker(actor, '咆哮！', '#e74c3c');
for (let i = 0; i < enemies.length; i++) {
  const dmg = Math.floor(actor.atk * 0.5);
  Effect.damage(actor, enemies[i], dmg);
}
Effect.modifyAttack(actor, 20, 2);

if (!actor._toughnessUsed && context.damage >= actor.hp) {
  actor._toughnessUsed = true;
  const heal = Math.floor(actor.maxHp * 0.2);
  Effect.heal(actor, actor, heal);
  Effect.showMarker(actor, '坚韧！', '#27ae60');
}

const target = await Effect.chooseEnemy(actor, { shape: '+', n: 3 });
if (!target) return;
const dmg = actor.atk;
Effect.damage(actor, target, dmg);
Effect.showMarker(target, '武圣！', '#e74c3c');
if (target.hp <= 0) {
  Effect.modifyAttack(actor, 30, 2);
}

if (!actor._undyingUsed && context.damage >= actor.hp) {
  actor._undyingUsed = true;
  Effect.addMark(actor, '不屈', 1);
  Effect.showMarker(actor, '不屈！', '#27ae60');
}

const target = await Effect.chooseCell(actor, { shape: 'r', n: 2 });
if (!target) return;
const enemies = Effect.getEnemiesAt(target.x, target.y, { shape: '+', n: 1 });
Effect.showMarker(actor, '火攻！', '#e67e22');
for (let i = 0; i < enemies.length; i++) {
  const dmg = Math.floor(actor.atk * 0.6);
  Effect.damage(actor, enemies[i], dmg);
  Effect.addMark(enemies[i], '灼烧', 3);
}

const target = await Effect.chooseCell(actor, { shape: 'r', n: 2 });
if (!target) return;
Effect.placeTrap(target.x, target.y, { owner: actor, damage: Math.floor(actor.atk * 0.8) });
Effect.showMarker({x: target.x, y: target.y}, '陷阱', '#9b59b6');

const target = await Effect.chooseCell(actor, { shape: '+', n: 2 });
if (!target) return;
Effect.teleport(actor, target.x, target.y);
Effect.showMarker(actor, '龙胆！', '#3498db');
const enemies = Effect.getEnemiesInRange(actor, { shape: '+', n: 1 });
for (let i = 0; i < enemies.length; i++) {
  const dmg = Math.floor(actor.atk * 0.7);
  Effect.damage(actor, enemies[i], dmg);
}

const target = await Effect.chooseEnemy(actor, { shape: 'r', n: 3 });
if (!target) return;
Effect.addMark(target, '破阵标记', 3);
Effect.showMarker(target, '标记！', '#f39c12');

const allies = Effect.getAlliesInRange(actor, { shape: 'r', n: 1 });
if (allies.length === 0) { Game.log('周围没有友军！', 'turn'); return; }
Effect.showMarker(actor, '倾城！', '#e91e63');
for (let i = 0; i < allies.length; i++) {
  const heal = Math.floor(actor.atk * 0.8);
  Effect.heal(actor, allies[i], heal);
}

const allies = Effect.getAlliesInRange(actor, { shape: 'r', n: 1 });
for (let i = 0; i < allies.length; i++) {
  Effect.addMark(allies[i], '红颜守护', 1);
}
Effect.showMarker(actor, '红颜守护', '#e91e63');

Effect.addMark(actor, '隐身', 2);
Effect.modifyAttack(actor, Math.floor(actor.atk * 0.3), 2);
Effect.showMarker(actor, '奸雄！', '#8e44ad');

const target = await Effect.chooseEnemy(actor, { shape: '+', n: 1 });
if (!target) return;
const stealAtk = Math.floor(target.atk * 0.2);
const stealDef = Math.floor(target.def * 0.2);
Effect.modifyAttack(actor, stealAtk, 3);
Effect.modifyDef(actor, stealDef, 3);
Effect.modifyAttack(target, -stealAtk, 3);
Effect.modifyDef(target, -stealDef, 3);
Effect.showMarker(actor, '挟天子！', '#8e44ad');

actor.moved = false;
actor.attacked = false;
Effect.addMark(actor, '铁骑', 1);
Effect.modifyAttackRange(actor, 1, 1);
Effect.showMarker(actor, '铁骑！', '#c0392b');

if (!actor._reviveUsed) {
  actor._reviveUsed = true;
  Effect.addMark(actor, '复活等待', 2);
  Effect.showMarker(actor, '待复活...', '#27ae60');
}

const target = await Effect.chooseCell(actor, { shape: 'r', n: 2 });
if (!target) return;
const half = Math.floor(Range.BOARD_SIZE / 2);
const isOwnHalf = actor.side === 'red' ? target.y >= half : target.y < half;
if (!isOwnHalf) {
  Game.log('只能召唤到己方半场！', 'turn');
  return;
}
Effect.summonMinion(actor, 'minion_sword', target.x, target.y);
Effect.showMarker(actor, '伏兵！', '#795548');

const allies = Effect.getAlliesInRange(actor, { shape: 'r', n: 1 });
if (allies.length === 0) {
  Effect.modifyDef(actor, 20, 3);
} else {
  for (let i = 0; i < allies.length; i++) {
    Effect.modifyDef(allies[i], 20, 3);
  }
  Effect.modifyDef(actor, 20, 3);
}
Effect.showMarker(actor, '坚守！', '#2980b9');

// 在十字3格范围内选择一名敌人，造成 1.5 倍攻击力伤害
const target = await Effect.chooseEnemy(actor, {
  range: { shape: "+", n: 3 },
  hintText: "请选择敌人"
});
if (!target) return false;
actor.skilled = true;
Effect.damage(actor, target, Effect.getEffectiveAttack(actor), { mul: 1.5 });
global.Game.log(actor.name + " 发动技能！");
return true;

var allies = Effect.searchPiece({shape:"r",n:3,center:{x:actor.x,y:actor.y}}, {side:"ally"}, {actor:actor});
allies.forEach(function(a){ Effect.heal(a, 40); });
Game.log(actor.name + " 施展太平治愈，范围内友军恢复生命！");

var allies = Effect.searchPiece({shape:"+",n:2,center:{x:actor.x,y:actor.y}}, {side:"ally"}, {actor:actor});
allies.forEach(function(a){ Effect.shield(a, 20); });
Game.log(actor.name + " 为周围友军施加地公护盾！");

Effect.deployMinion("huangjin_soldier", actor.x - 1, actor.y, { side: actor.side, ignoreCost: true, ignoreLimit: true, ignoreHalf: true });
Effect.deployMinion("huangjin_soldier", actor.x + 1, actor.y, { side: actor.side, ignoreCost: true, ignoreLimit: true, ignoreHalf: true });
Game.log(actor.name + " 召集了两名黄巾兵！");
